scripts:
(function() {
  const unitRadios = document.querySelectorAll('input[name="mcp-unit"]');
  const lengthInput = document.getElementById('mcp-length');
  const widthInput  = document.getElementById('mcp-width');
  const depthInput  = document.getElementById('mcp-depth');
  const bagSelect   = document.getElementById('mcp-bag-size');
  const wasteRange  = document.getElementById('mcp-waste');
  const wasteValue  = document.getElementById('mcp-waste-value');
  const resultsBox  = document.getElementById('mcp-results');

  const lengthLabel = document.getElementById('mcp-length-label');
  const widthLabel  = document.getElementById('mcp-width-label');
  const depthLabel  = document.getElementById('mcp-depth-label');

  let currentUnit = 'metric';

  const bagYieldsM3 = {
    20: 0.009, // m³ per 20 kg bag (approx)
    25: 0.011, // m³ per 25 kg bag (approx)
    40: 0.018  // m³ per 40 kg bag (approx)
  };

  function updateLabels() {
    if (currentUnit === 'metric') {
      lengthLabel.textContent = 'Length (m)';
      widthLabel.textContent  = 'Width (m)';
      depthLabel.textContent  = 'Thickness (cm)';
      lengthInput.placeholder = 'e.g. 3';
      widthInput.placeholder  = 'e.g. 2';
      depthInput.placeholder  = 'e.g. 10';
    } else {
      lengthLabel.textContent = 'Length (ft)';
      widthLabel.textContent  = 'Width (ft)';
      depthLabel.textContent  = 'Thickness (in)';
      lengthInput.placeholder = 'e.g. 10';
      widthInput.placeholder  = 'e.g. 8';
      depthInput.placeholder  = 'e.g. 4';
    }
  }

  function format(num, decimals) {
    return Number.isFinite(num) ? num.toFixed(decimals) : '-';
  }

  function calculate() {
    const L = parseFloat(lengthInput.value);
    const W = parseFloat(widthInput.value);
    const D = parseFloat(depthInput.value);
    const bagSize = parseInt(bagSelect.value, 10);
    const waste   = parseFloat(wasteRange.value);

    wasteValue.textContent = waste.toString();

    if (!L || !W || !D || L <= 0 || W <= 0 || D <= 0) {
      resultsBox.innerHTML = '<strong>Results</strong><p>Please enter all dimensions above to see the calculation.</p>';
      return;
    }

    let volumeM3;
    let volumeFt3;

    if (currentUnit === 'metric') {
      const depthM = D / 100; // cm → m
      volumeM3 = L * W * depthM;
      volumeFt3 = volumeM3 / 0.0283168;
    } else {
      const depthFt = D / 12; // in → ft
      volumeFt3 = L * W * depthFt;
      volumeM3 = volumeFt3 * 0.0283168;
    }

    const volumeM3Waste = volumeM3 * (1 + waste / 100);
    const yieldPerBag   = bagYieldsM3[bagSize] || 0.011;
    const bagsNeeded    = Math.ceil(volumeM3Waste / yieldPerBag);

    resultsBox.innerHTML = `
      <strong>Results</strong>
      <p><strong>Net volume:</strong> ${format(volumeM3, 3)} m³ (${format(volumeFt3, 1)} ft³)</p>
      <p><strong>Volume incl. ${waste.toFixed(0)}% waste:</strong> ${format(volumeM3Waste, 3)} m³</p>
      <p><strong>Estimated bags (${bagSize} kg):</strong> ${bagsNeeded} bags</p>
      <p style="margin-top:0.4rem;">Tip: If you are close to a whole number, round <em>up</em> to avoid running short on site.</p>
    `;
  }

  unitRadios.forEach(radio => {
    radio.addEventListener('change', () => {
      currentUnit = radio.value;
      updateLabels();
      calculate();
    });
  });

  [lengthInput, widthInput, depthInput, bagSelect, wasteRange].forEach(el => {
    el.addEventListener('input', calculate);
  });

  // initial
  updateLabels();
  calculate();
})();

styles:
.mcp-calc-wrapper {
    max-width: 640px;
    margin: 1.5rem 0 2.5rem;
    padding: 1.5rem 1.75rem;
    border-radius: 12px;
    border: 2px solid #1a28ff;
    background: rgba(255,255,255,0.04);
    font-family: system-ui, -apple-system, BlinkMacSystemFont, "SF Mono", monospace;
  }

  .mcp-calc-wrapper h3 {
    margin-top: 0;
    margin-bottom: 1rem;
    font-size: 1.2rem;
  }

  .mcp-calc-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 0.75rem 1.25rem;
  }

  .mcp-calc-field {
    display: flex;
    flex-direction: column;
    font-size: 0.9rem;
  }

  .mcp-calc-field label {
    margin-bottom: 0.25rem;
  }

  .mcp-calc-field input,
  .mcp-calc-field select {
    padding: 0.35rem 0.45rem;
    border-radius: 6px;
    border: 1px solid #4a4aff;
    background: rgba(0,0,0,0.05);
    color: inherit;
  }

  .mcp-calc-field input:focus,
  .mcp-calc-field select:focus {
    outline: 2px solid #1a28ff;
    outline-offset: 1px;
  }

  .mcp-unit-toggle {
    display: flex;
    gap: 1rem;
    margin-bottom: 0.75rem;
    font-size: 0.9rem;
  }

  .mcp-unit-toggle label {
    display: inline-flex;
    align-items: center;
    gap: 0.25rem;
  }

  .mcp-waste-row {
    grid-column: 1 / -1;
    display: flex;
    align-items: center;
    gap: 0.5rem;
    font-size: 0.9rem;
  }

  .mcp-waste-row input[type="range"] {
    flex: 1;
  }

  .mcp-results {
    margin-top: 1.25rem;
    padding-top: 1rem;
    border-top: 1px dashed #4a4aff;
    font-size: 0.95rem;
  }

  .mcp-results strong {
    display: block;
    margin-bottom: 0.35rem;
  }

  .mcp-results p {
    margin: 0.1rem 0;
  }

  .mcp-note {
    margin-top: 0.75rem;
    font-size: 0.8rem;
    opacity: 0.85;
  }

  @media (max-width: 640px) {
    .mcp-calc-grid {
      grid-template-columns: 1fr;
    }
    .mcp-waste-row {
      flex-direction: column;
      align-items: flex-start;
    }
  }

scripts:
(function () {
    const el = {
      len: document.getElementById("mcpPaintLen"),
      wid: document.getElementById("mcpPaintWid"),
      height: document.getElementById("mcpPaintHeight"),
      coats: document.getElementById("mcpPaintCoats"),
      doors: document.getElementById("mcpPaintDoors"),
      windows: document.getElementById("mcpPaintWindows"),
      coverage: document.getElementById("mcpPaintCoverage"),
      results: document.getElementById("mcpPaintResults"),
      coverageLabel: document.getElementById("mcpPaintCoverageLabel"),
      coverageHelp: document.getElementById("mcpPaintCoverageHelp"),
      lenHelp: document.getElementById("mcpPaintLenHelp"),
      widHelp: document.getElementById("mcpPaintWidHelp"),
      heightHelp: document.getElementById("mcpPaintHeightHelp"),
      doorsHelp: document.getElementById("mcpPaintDoorsHelp"),
      windowsHelp: document.getElementById("mcpPaintWindowsHelp")
    };

    const unitRadios = document.querySelectorAll("input[name='mcpPaintUnits']");

    function getUnit() {
      for (const r of unitRadios) {
        if (r.checked) return r.value;
      }
      return "metric";
    }

    function updateLabels() {
      const unit = getUnit();

      if (unit === "metric") {
        el.lenHelp.textContent = "meters";
        el.widHelp.textContent = "meters";
        el.heightHelp.textContent = "meters (floor to ceiling)";
        el.doorsHelp.textContent = "m² of doors to subtract (optional)";
        el.windowsHelp.textContent = "m² of windows to subtract (optional)";
        el.coverageLabel.textContent = "Paint coverage per liter";
        el.coverage.value = el.coverage.value || 10;
        el.coverageHelp.textContent =
          "Typical interior paint covers ~10 m² per liter.";
      } else {
        el.lenHelp.textContent = "feet";
        el.widHelp.textContent = "feet";
        el.heightHelp.textContent = "feet (floor to ceiling)";
        el.doorsHelp.textContent = "ft² of doors to subtract (optional)";
        el.windowsHelp.textContent = "ft² of windows to subtract (optional)";
        el.coverageLabel.textContent = "Paint coverage per gallon";
        el.coverage.value = el.coverage.value || 350;
        el.coverageHelp.textContent =
          "Typical interior paint covers ~350 ft² per gallon.";
      }
      calculate();
    }

    function num(value) {
      const n = parseFloat(value);
      return isNaN(n) ? 0 : n;
    }

    function calculate() {
      const unit = getUnit();

      const L = num(el.len.value);
      const W = num(el.wid.value);
      const H = num(el.height.value);
      let coats = num(el.coats.value);
      const doors = num(el.doors.value);
      const windows = num(el.windows.value);
      const coverage = num(el.coverage.value);

      if (!L || !W || !H || !coverage) {
        el.results.innerHTML =
          "<p><strong>Please enter length, width, height and coverage.</strong></p>";
        return;
      }

      if (coats < 1) coats = 1;

      // wall area before openings
      let wallArea, totalArea, liters, gallons, areaM2, areaFt2;

      if (unit === "metric") {
        wallArea = 2 * (L + W) * H - doors - windows; // m²
        wallArea = Math.max(0, wallArea);
        totalArea = wallArea * coats; // m²
        liters = totalArea / coverage;
        gallons = liters * 0.264172;
        areaM2 = totalArea;
        areaFt2 = totalArea * 10.7639;
      } else {
        wallArea = 2 * (L + W) * H - doors - windows; // ft²
        wallArea = Math.max(0, wallArea);
        totalArea = wallArea * coats; // ft²
        gallons = totalArea / coverage;
        liters = gallons * 3.78541;
        areaFt2 = totalArea;
        areaM2 = totalArea * 0.092903;
      }

      const safeLiters = Math.ceil(liters * 10) / 10; // round up to 0.1 L
      const safeGallons = Math.ceil(gallons * 100) / 100; // round up to 0.01 gal

      const html = `
        <p><strong>Total wall area (all coats):</strong> 
          ${areaM2.toFixed(2)} m²  (${areaFt2.toFixed(0)} ft²)
        </p>
        <p><strong>Estimated paint required:</strong> 
          ${liters.toFixed(2)} L  (${gallons.toFixed(2)} gal)
        </p>
        <p><strong>Recommended to buy at least:</strong> 
          ${safeLiters.toFixed(1)} L  (~${safeGallons.toFixed(2)} gal)
        </p>
      `;

      el.results.innerHTML = html;
    }

    // events
    [
      el.len,
      el.wid,
      el.height,
      el.coats,
      el.doors,
      el.windows,
      el.coverage
    ].forEach((input) => {
      input.addEventListener("input", calculate);
    });

    unitRadios.forEach((radio) =>
      radio.addEventListener("change", updateLabels)
    );

    updateLabels();
  })();

