(function () {
    const els = {
      len: document.getElementById("mcpFloorLen"),
      wid: document.getElementById("mcpFloorWid"),
      extra: document.getElementById("mcpFloorExtra"),
      waste: document.getElementById("mcpFloorWaste"),
      coverage: document.getElementById("mcpFloorCoverage"),
      results: document.getElementById("mcpFloorResults"),
      lenHelp: document.getElementById("mcpFloorLenHelp"),
      widHelp: document.getElementById("mcpFloorWidHelp"),
      extraHelp: document.getElementById("mcpFloorExtraHelp"),
      coverageHelp: document.getElementById("mcpFloorCoverageHelp")
    };

    const unitRadios = document.querySelectorAll("input[name='mcpFloorUnits']");

    function getUnit() {
      for (const r of unitRadios) {
        if (r.checked) return r.value;
      }
      return "metric";
    }

    function num(v) {
      const n = parseFloat(v);
      return isNaN(n) ? 0 : n;
    }

    function updateLabels() {
      const unit = getUnit();
      if (unit === "metric") {
        els.lenHelp.textContent = "meters";
        els.widHelp.textContent = "meters";
        els.extraHelp.textContent = "extra m² (optional)";
        els.coverageHelp.textContent =
          "Metric: m² per box (often 1.5–2.5 m²). Imperial: ft² per box if using ft.";
        if (!els.coverage.value) els.coverage.value = 2;
      } else {
        els.lenHelp.textContent = "feet";
        els.widHelp.textContent = "feet";
        els.extraHelp.textContent = "extra ft² (optional)";
        els.coverageHelp.textContent =
          "Imperial: ft² per box (e.g. 20–30 ft²). Metric: m² per box if using m.";
        if (!els.coverage.value) els.coverage.value = 200;
      }
      calculate();
    }

    function calculate() {
      const unit = getUnit();
      const L = num(els.len.value);
      const W = num(els.wid.value);
      const extra = num(els.extra.value);
      let waste = num(els.waste.value);
      const coverage = num(els.coverage.value);

      if (!L || !W || L <= 0 || W <= 0) {
        els.results.innerHTML =
          "<p><strong>Please enter room length and width.</strong></p>";
        return;
      }

      if (waste < 0) waste = 0;
      if (waste > 20) waste = 20;

      // base area
      let areaBase = L * W; // m² or ft² depending on unit
      let areaTotal = areaBase + (extra > 0 ? extra : 0);

      // convert to both m² and ft² for display
      let areaM2, areaFt2;
      if (unit === "metric") {
        areaM2 = areaTotal;
        areaFt2 = areaTotal * 10.7639;
      } else {
        areaFt2 = areaTotal;
        areaM2 = areaTotal * 0.092903;
      }

      const areaWithWaste = areaTotal * (1 + waste / 100);

      let boxesText = "";
      if (coverage > 0) {
        const boxes = areaWithWaste / coverage;
        const boxesRounded = Math.ceil(boxes);
        boxesText = `<p><strong>Estimated boxes (incl. waste):</strong> ${boxesRounded} boxes</p>`;
      }

      els.results.innerHTML = `
        <p><strong>Floor area (no waste):</strong> ${areaM2.toFixed(
          2
        )} m² (${areaFt2.toFixed(0)} ft²)</p>
        <p><strong>Area incl. ${waste.toFixed(
          0
        )}% waste:</strong> ${areaWithWaste.toFixed(2)} ${
        unit === "metric" ? "m²" : "ft²"
      }</p>
        ${boxesText}
      `;
    }

    unitRadios.forEach((r) => r.addEventListener("change", updateLabels));
    [els.len, els.wid, els.extra, els.waste, els.coverage].forEach((input) =>
      input.addEventListener("input", calculate)
    );

    updateLabels();
  })();

