scripts:
(function () {
    const els = {
      len: document.getElementById("mcpAsphaltLen"),
      wid: document.getElementById("mcpAsphaltWid"),
      depth: document.getElementById("mcpAsphaltDepth"),
      waste: document.getElementById("mcpAsphaltWaste"),
      density: document.getElementById("mcpAsphaltDensity"),
      results: document.getElementById("mcpAsphaltResults"),
      lenHelp: document.getElementById("mcpAsphaltLenHelp"),
      widHelp: document.getElementById("mcpAsphaltWidHelp"),
      depthHelp: document.getElementById("mcpAsphaltDepthHelp")
    };

    const unitRadios = document.querySelectorAll(
      "input[name='mcpAsphaltUnits']"
    );

    function getUnit() {
      for (const r of unitRadios) {
        if (r.checked) return r.value;
      }
      return "metric";
    }

    function num(v) {
      const n = parseFloat(v);
      return isNaN(n) ? 0 : n;
    }

    function updateLabels() {
      const unit = getUnit();
      if (unit === "metric") {
        els.lenHelp.textContent = "meters";
        els.widHelp.textContent = "meters";
        els.depthHelp.textContent = "centimeters (typical 5–10 cm)";
        if (!els.density.value) els.density.value = 2.4;
      } else {
        els.lenHelp.textContent = "feet";
        els.widHelp.textContent = "feet";
        els.depthHelp.textContent = "inches (typical 2–4 in)";
        if (!els.density.value) els.density.value = 150; // lb/ft³ approx, but we'll still treat as t/m³ via conversion
      }
      calculate();
    }

    function calculate() {
      const unit = getUnit();
      const L = num(els.len.value);
      const W = num(els.wid.value);
      const D = num(els.depth.value);
      let waste = num(els.waste.value);
      let density = num(els.density.value);

      if (!L || !W || !D || L <= 0 || W <= 0 || D <= 0) {
        els.results.innerHTML =
          "<p><strong>Please enter length, width and thickness.</strong></p>";
        return;
      }

      if (waste < 0) waste = 0;
      if (waste > 20) waste = 20;

      let volumeM3, volumeFt3;

      if (unit === "metric") {
        const depthM = D / 100; // cm → m
        volumeM3 = L * W * depthM;
        volumeFt3 = volumeM3 / 0.0283168;
        if (!density || density < 1) density = 2.4; // t/m³
      } else {
        const depthFt = D / 12; // in → ft
        volumeFt3 = L * W * depthFt;
        volumeM3 = volumeFt3 * 0.0283168;
        if (!density || density < 10) {
          // If user gave lb/ft³, convert approx
          density = 2.4;
        }
      }

      const volumeWithWaste = volumeM3 * (1 + waste / 100);
      const tonnes = volumeWithWaste * density;
      const kg = tonnes * 1000;
      const usTons = tonnes * 1.10231;
      const cubicYards = volumeWithWaste * 1.30795;

      // Rough truckload estimate (10 t truck)
      const truckCapacityT = 10;
      const truckLoads = Math.ceil(tonnes / truckCapacityT);

      els.results.innerHTML = `
        <p><strong>Net volume:</strong> ${volumeM3.toFixed(
          3
        )} m³ (${volumeFt3.toFixed(1)} ft³)</p>
        <p><strong>Volume incl. ${waste.toFixed(
          0
        )}% waste/compaction:</strong> ${volumeWithWaste.toFixed(
        3
      )} m³ (~${cubicYards.toFixed(2)} yd³)</p>
        <p><strong>Estimated weight:</strong> ${tonnes.toFixed(
          2
        )} tonnes (${kg.toFixed(0)} kg, ~${usTons.toFixed(2)} US tons)</p>
        <p><strong>Approx. truck loads (10 t each):</strong> ${truckLoads} load(s)</p>
      `;
    }

    unitRadios.forEach((r) => r.addEventListener("change", updateLabels));
    [els.len, els.wid, els.depth, els.waste, els.density].forEach((input) =>
      input.addEventListener("input", calculate)
    );

    updateLabels();
  })();

