scripts:
(function () {
    const els = {
      length: document.getElementById("mcpFenceLength"),
      spacing: document.getElementById("mcpFenceSpacing"),
      diameter: document.getElementById("mcpFenceDiameter"),
      depth: document.getElementById("mcpFenceDepth"),
      waste: document.getElementById("mcpFenceWaste"),
      bagYield: document.getElementById("mcpFenceBagYield"),
      results: document.getElementById("mcpFenceResults"),
      lengthHelp: document.getElementById("mcpFenceLengthHelp"),
      spacingHelp: document.getElementById("mcpFenceSpacingHelp"),
      diameterHelp: document.getElementById("mcpFenceDiameterHelp"),
      depthHelp: document.getElementById("mcpFenceDepthHelp"),
      bagYieldHelp: document.getElementById("mcpFenceBagYieldHelp")
    };

    const unitRadios = document.querySelectorAll("input[name='mcpFenceUnits']");

    function getUnit() {
      for (const r of unitRadios) {
        if (r.checked) return r.value;
      }
      return "metric";
    }

    function num(v) {
      const n = parseFloat(v);
      return isNaN(n) ? 0 : n;
    }

    function updateLabels() {
      const unit = getUnit();
      if (unit === "metric") {
        els.lengthHelp.textContent = "meters";
        els.spacingHelp.textContent = "meters between posts";
        els.diameterHelp.textContent = "centimeters (hole diameter)";
        els.depthHelp.textContent = "centimeters (hole depth)";
        els.bagYieldHelp.textContent =
          "Metric: m³ per bag (~0.02 m³ for 25 kg). Imperial: ft³ per bag (~0.6 ft³).";
        if (!els.bagYield.value) els.bagYield.value = 0.02;
      } else {
        els.lengthHelp.textContent = "feet";
        els.spacingHelp.textContent = "feet between posts";
        els.diameterHelp.textContent = "inches (hole diameter)";
        els.depthHelp.textContent = "inches (hole depth)";
        els.bagYieldHelp.textContent =
          "Imperial: ft³ per bag (~0.6 ft³ typical). Metric: m³ per bag if using m.";
        if (!els.bagYield.value) els.bagYield.value = 0.6;
      }
      calculate();
    }

    function calculate() {
      const unit = getUnit();
      const fenceLen = num(els.length.value);
      const spacing = num(els.spacing.value);
      const dia = num(els.diameter.value);
      const depth = num(els.depth.value);
      let waste = num(els.waste.value);
      const bagYield = num(els.bagYield.value);

      if (!fenceLen || !spacing || !dia || !depth || fenceLen <= 0 || spacing <= 0 || dia <= 0 || depth <= 0) {
        els.results.innerHTML =
          "<p><strong>Please enter fence length, spacing and hole size.</strong></p>";
        return;
      }

      if (waste < 0) waste = 0;
      if (waste > 25) waste = 25;

      // number of spaces between posts
      const spaces = fenceLen / spacing;
      let posts = Math.floor(spaces) + 1;
      if (spaces % 1 !== 0) {
        // if not exact, add one more post at the end
        posts += 0;
      }
      posts = Math.max(2, posts);

      let volumePerHoleM3, totalVolumeM3;

      if (unit === "metric") {
        const radiusM = (dia / 100) / 2; // cm -> m, then radius
        const depthM = depth / 100;      // cm -> m
        volumePerHoleM3 = Math.PI * radiusM * radiusM * depthM;
      } else {
        const radiusFt = (dia / 12) / 2; // in -> ft, then radius
        const depthFt = depth / 12;      // in -> ft
        const volumePerHoleFt3 = Math.PI * radiusFt * radiusFt * depthFt;
        const totalVolumeFt3 = volumePerHoleFt3 * posts;
        volumePerHoleM3 = volumePerHoleFt3 * 0.0283168;
        totalVolumeM3 = totalVolumeFt3 * 0.0283168;
      }

      if (unit === "metric") {
        totalVolumeM3 = volumePerHoleM3 * posts;
      }

      const totalVolumeWithWaste = totalVolumeM3 * (1 + waste / 100);
      const totalVolumeFt3 = totalVolumeM3 / 0.0283168;

      let bags = 0;
      if (bagYield > 0) {
        if (unit === "metric") {
          bags = totalVolumeWithWaste / bagYield;
        } else {
          // bagYield is in ft³ in imperial mode
          const totalVolFt3Waste = totalVolumeFt3 * (1 + waste / 100);
          bags = totalVolFt3Waste / bagYield;
        }
      }

      const bagsRounded = bags > 0 ? Math.ceil(bags) : 0;

      els.results.innerHTML = `
        <p><strong>Number of posts (approx.):</strong> ${posts}</p>
        <p><strong>Concrete per hole:</strong> ${volumePerHoleM3.toFixed(
          3
        )} m³ (${(volumePerHoleM3 / 0.0283168).toFixed(1)} ft³)</p>
        <p><strong>Total concrete (no extra):</strong> ${totalVolumeM3.toFixed(
          3
        )} m³ (${totalVolumeFt3.toFixed(1)} ft³)</p>
        <p><strong>Total incl. ${waste.toFixed(
          0
        )}% extra:</strong> ${totalVolumeWithWaste.toFixed(
        3
      )} m³ (~${(totalVolumeWithWaste / 0.0283168).toFixed(1)} ft³)</p>
        ${
          bagsRounded
            ? `<p><strong>Recommended bags (approx.):</strong> ${bagsRounded} bag(s)</p>`
            : ""
        }
      `;
    }

    unitRadios.forEach((r) => r.addEventListener("change", updateLabels));
    [
      els.length,
      els.spacing,
      els.diameter,
      els.depth,
      els.waste,
      els.bagYield
    ].forEach((input) => input.addEventListener("input", calculate));

    updateLabels();
  })();

