scripts:
(function () {
    const els = {
      len: document.getElementById("mcpBrickLen"),
      height: document.getElementById("mcpBrickHeight"),
      rate: document.getElementById("mcpBrickRate"),
      waste: document.getElementById("mcpBrickWaste"),
      perPallet: document.getElementById("mcpBrickPerPallet"),
      results: document.getElementById("mcpBrickResults"),
      lenHelp: document.getElementById("mcpBrickLenHelp"),
      heightHelp: document.getElementById("mcpBrickHeightHelp"),
      rateHelp: document.getElementById("mcpBrickRateHelp")
    };

    const unitRadios = document.querySelectorAll("input[name='mcpBrickUnits']");

    function getUnit() {
      for (const r of unitRadios) {
        if (r.checked) return r.value;
      }
      return "metric";
    }

    function num(v) {
      const n = parseFloat(v);
      return isNaN(n) ? 0 : n;
    }

    function updateLabels() {
      const unit = getUnit();
      if (unit === "metric") {
        els.lenHelp.textContent = "meters";
        els.heightHelp.textContent = "meters";
        els.rateHelp.textContent =
          "Typical single-skin wall: ~60 bricks per m² (including joints).";
        if (!els.rate.value) els.rate.value = 60;
      } else {
        els.lenHelp.textContent = "feet";
        els.heightHelp.textContent = "feet";
        els.rateHelp.textContent =
          "Single-skin wall: typically 6–8 bricks per ft². Default ~7.5 bricks/ft².";
        if (!els.rate.value) els.rate.value = 7.5;
      }
      calculate();
    }

    function calculate() {
      const unit = getUnit();
      const L = num(els.len.value);
      const H = num(els.height.value);
      let rate = num(els.rate.value);
      let waste = num(els.waste.value);
      const perPallet = num(els.perPallet.value);

      if (!L || !H || L <= 0 || H <= 0) {
        els.results.innerHTML =
          "<p><strong>Please enter wall length and height.</strong></p>";
        return;
      }

      if (waste < 0) waste = 0;
      if (waste > 20) waste = 20;

      if (!rate || rate <= 0) {
        rate = unit === "metric" ? 60 : 7.5;
      }

      // base area
      let area = L * H; // m² or ft² depending on unit

      // convert area to both systems for display
      let areaM2, areaFt2;
      if (unit === "metric") {
        areaM2 = area;
        areaFt2 = area * 10.7639;
      } else {
        areaFt2 = area;
        areaM2 = area * 0.092903;
      }

      const netBricks = area * rate;
      const bricksWithWaste = netBricks * (1 + waste / 100);
      const totalBricks = Math.ceil(bricksWithWaste);

      let palletText = "";
      if (perPallet > 0) {
        const pallets = Math.ceil(totalBricks / perPallet);
        palletText = `<p><strong>Approx. pallets/packs needed:</strong> ${pallets}</p>`;
      }

      els.results.innerHTML = `
        <p><strong>Wall area:</strong> ${areaM2.toFixed(
          2
        )} m² (${areaFt2.toFixed(0)} ft²)</p>
        <p><strong>Net bricks (no waste):</strong> ${Math.ceil(
          netBricks
        )} bricks</p>
        <p><strong>Bricks incl. ${waste.toFixed(
          0
        )}% waste:</strong> ${totalBricks} bricks</p>
        ${palletText}
      `;
    }

    unitRadios.forEach((r) => r.addEventListener("change", updateLabels));
    [
      els.len,
      els.height,
      els.rate,
      els.waste,
      els.perPallet
    ].forEach((input) => input.addEventListener("input", calculate));

    updateLabels();
  })();

