scripts:
(function () {
    const el = {
      len: document.getElementById("mcpPaintLen"),
      wid: document.getElementById("mcpPaintWid"),
      height: document.getElementById("mcpPaintHeight"),
      coats: document.getElementById("mcpPaintCoats"),
      doors: document.getElementById("mcpPaintDoors"),
      windows: document.getElementById("mcpPaintWindows"),
      coverage: document.getElementById("mcpPaintCoverage"),
      results: document.getElementById("mcpPaintResults"),
      coverageLabel: document.getElementById("mcpPaintCoverageLabel"),
      coverageHelp: document.getElementById("mcpPaintCoverageHelp"),
      lenHelp: document.getElementById("mcpPaintLenHelp"),
      widHelp: document.getElementById("mcpPaintWidHelp"),
      heightHelp: document.getElementById("mcpPaintHeightHelp"),
      doorsHelp: document.getElementById("mcpPaintDoorsHelp"),
      windowsHelp: document.getElementById("mcpPaintWindowsHelp")
    };

    const unitRadios = document.querySelectorAll("input[name='mcpPaintUnits']");

    function getUnit() {
      for (const r of unitRadios) {
        if (r.checked) return r.value;
      }
      return "metric";
    }

    function updateLabels() {
      const unit = getUnit();

      if (unit === "metric") {
        el.lenHelp.textContent = "meters";
        el.widHelp.textContent = "meters";
        el.heightHelp.textContent = "meters (floor to ceiling)";
        el.doorsHelp.textContent = "m² of doors to subtract (optional)";
        el.windowsHelp.textContent = "m² of windows to subtract (optional)";
        el.coverageLabel.textContent = "Paint coverage per liter";
        el.coverage.value = el.coverage.value || 10;
        el.coverageHelp.textContent =
          "Typical interior paint covers ~10 m² per liter.";
      } else {
        el.lenHelp.textContent = "feet";
        el.widHelp.textContent = "feet";
        el.heightHelp.textContent = "feet (floor to ceiling)";
        el.doorsHelp.textContent = "ft² of doors to subtract (optional)";
        el.windowsHelp.textContent = "ft² of windows to subtract (optional)";
        el.coverageLabel.textContent = "Paint coverage per gallon";
        el.coverage.value = el.coverage.value || 350;
        el.coverageHelp.textContent =
          "Typical interior paint covers ~350 ft² per gallon.";
      }
      calculate();
    }

    function num(value) {
      const n = parseFloat(value);
      return isNaN(n) ? 0 : n;
    }

    function calculate() {
      const unit = getUnit();

      const L = num(el.len.value);
      const W = num(el.wid.value);
      const H = num(el.height.value);
      let coats = num(el.coats.value);
      const doors = num(el.doors.value);
      const windows = num(el.windows.value);
      const coverage = num(el.coverage.value);

      if (!L || !W || !H || !coverage) {
        el.results.innerHTML =
          "<p><strong>Please enter length, width, height and coverage.</strong></p>";
        return;
      }

      if (coats < 1) coats = 1;

      // wall area before openings
      let wallArea, totalArea, liters, gallons, areaM2, areaFt2;

      if (unit === "metric") {
        wallArea = 2 * (L + W) * H - doors - windows; // m²
        wallArea = Math.max(0, wallArea);
        totalArea = wallArea * coats; // m²
        liters = totalArea / coverage;
        gallons = liters * 0.264172;
        areaM2 = totalArea;
        areaFt2 = totalArea * 10.7639;
      } else {
        wallArea = 2 * (L + W) * H - doors - windows; // ft²
        wallArea = Math.max(0, wallArea);
        totalArea = wallArea * coats; // ft²
        gallons = totalArea / coverage;
        liters = gallons * 3.78541;
        areaFt2 = totalArea;
        areaM2 = totalArea * 0.092903;
      }

      const safeLiters = Math.ceil(liters * 10) / 10; // round up to 0.1 L
      const safeGallons = Math.ceil(gallons * 100) / 100; // round up to 0.01 gal

      const html = `
        <p><strong>Total wall area (all coats):</strong> 
          ${areaM2.toFixed(2)} m²  (${areaFt2.toFixed(0)} ft²)
        </p>
        <p><strong>Estimated paint required:</strong> 
          ${liters.toFixed(2)} L  (${gallons.toFixed(2)} gal)
        </p>
        <p><strong>Recommended to buy at least:</strong> 
          ${safeLiters.toFixed(1)} L  (~${safeGallons.toFixed(2)} gal)
        </p>
      `;

      el.results.innerHTML = html;
    }

    // events
    [
      el.len,
      el.wid,
      el.height,
      el.coats,
      el.doors,
      el.windows,
      el.coverage
    ].forEach((input) => {
      input.addEventListener("input", calculate);
    });

    unitRadios.forEach((radio) =>
      radio.addEventListener("change", updateLabels)
    );

    updateLabels();
  })();

