scripts:
(function () {
    const els = {
      lenRoom: document.getElementById("mcpTileRoomLen"),
      widRoom: document.getElementById("mcpTileRoomWid"),
      lenTile: document.getElementById("mcpTileLen"),
      widTile: document.getElementById("mcpTileWid"),
      waste: document.getElementById("mcpTileWaste"),
      perBox: document.getElementById("mcpTilePerBox"),
      results: document.getElementById("mcpTileResults"),
      roomLenHelp: document.getElementById("mcpTileRoomLenHelp"),
      roomWidHelp: document.getElementById("mcpTileRoomWidHelp"),
      tileLenHelp: document.getElementById("mcpTileLenHelp"),
      tileWidHelp: document.getElementById("mcpTileWidHelp")
    };

    const unitRadios = document.querySelectorAll("input[name='mcpTileUnits']");

    function getUnit() {
      for (const r of unitRadios) {
        if (r.checked) return r.value;
      }
      return "metric";
    }

    function num(v) {
      const n = parseFloat(v);
      return isNaN(n) ? 0 : n;
    }

    function updateLabels() {
      const unit = getUnit();
      if (unit === "metric") {
        els.roomLenHelp.textContent = "meters";
        els.roomWidHelp.textContent = "meters";
        els.tileLenHelp.textContent = "centimeters";
        els.tileWidHelp.textContent = "centimeters";
        if (!els.lenTile.value && !els.widTile.value) {
          els.lenTile.placeholder = "e.g. 60";
          els.widTile.placeholder = "e.g. 30";
        }
      } else {
        els.roomLenHelp.textContent = "feet";
        els.roomWidHelp.textContent = "feet";
        els.tileLenHelp.textContent = "inches";
        els.tileWidHelp.textContent = "inches";
        if (!els.lenTile.value && !els.widTile.value) {
          els.lenTile.placeholder = "e.g. 24";
          els.widTile.placeholder = "e.g. 12";
        }
      }
      calculate();
    }

    function calculate() {
      const unit = getUnit();

      const Lr = num(els.lenRoom.value);
      const Wr = num(els.widRoom.value);
      const Lt = num(els.lenTile.value);
      const Wt = num(els.widTile.value);
      let waste = num(els.waste.value);
      const perBox = num(els.perBox.value);

      if (!Lr || !Wr || !Lt || !Wt || Lr <= 0 || Wr <= 0 || Lt <= 0 || Wt <= 0) {
        els.results.innerHTML =
          "<p><strong>Please enter floor size and tile size.</strong></p>";
        return;
      }

      if (waste < 0) waste = 0;
      if (waste > 30) waste = 30;

      let floorAreaM2, floorAreaFt2, tileAreaM2, tileAreaFt2;

      if (unit === "metric") {
        floorAreaM2 = Lr * Wr;
        tileAreaM2 = (Lt / 100) * (Wt / 100); // cm → m
        floorAreaFt2 = floorAreaM2 * 10.7639;
        tileAreaFt2 = tileAreaM2 * 10.7639;
      } else {
        floorAreaFt2 = Lr * Wr;
        tileAreaFt2 = (Lt / 12) * (Wt / 12); // in → ft
        floorAreaM2 = floorAreaFt2 * 0.092903;
        tileAreaM2 = floorAreaM2 / (Lr * Wr) * tileAreaFt2 || (tileAreaFt2 * 0.092903);
      }

      const netTiles = floorAreaM2 / tileAreaM2;
      const tilesWithWaste = netTiles * (1 + waste / 100);
      const totalTiles = Math.ceil(tilesWithWaste);

      let boxesText = "";
      if (perBox > 0) {
        const boxes = Math.ceil(totalTiles / perBox);
        boxesText = `<p><strong>Estimated boxes (at ${perBox} tiles/box):</strong> ${boxes} boxes</p>`;
      }

      els.results.innerHTML = `
        <p><strong>Total floor area:</strong> ${floorAreaM2.toFixed(
          2
        )} m² (${floorAreaFt2.toFixed(0)} ft²)</p>
        <p><strong>Net tiles (no waste):</strong> ${Math.ceil(
          netTiles
        )} tiles</p>
        <p><strong>Tiles incl. ${waste.toFixed(0)}% waste:</strong> ${totalTiles} tiles</p>
        ${boxesText}
      `;
    }

    unitRadios.forEach((r) => r.addEventListener("change", updateLabels));
    [
      els.lenRoom,
      els.widRoom,
      els.lenTile,
      els.widTile,
      els.waste,
      els.perBox
    ].forEach((input) => input.addEventListener("input", calculate));

    updateLabels();
  })();

