scripts:
(function () {
    const els = {
      len: document.getElementById("mcpGravelLen"),
      wid: document.getElementById("mcpGravelWid"),
      depth: document.getElementById("mcpGravelDepth"),
      waste: document.getElementById("mcpGravelWaste"),
      density: document.getElementById("mcpGravelDensity"),
      results: document.getElementById("mcpGravelResults"),
      lenHelp: document.getElementById("mcpGravelLenHelp"),
      widHelp: document.getElementById("mcpGravelWidHelp"),
      depthHelp: document.getElementById("mcpGravelDepthHelp")
    };

    const unitRadios = document.querySelectorAll("input[name='mcpGravelUnits']");

    function getUnit() {
      for (const r of unitRadios) {
        if (r.checked) return r.value;
      }
      return "metric";
    }

    function num(v) {
      const n = parseFloat(v);
      return isNaN(n) ? 0 : n;
    }

    function updateLabels() {
      const unit = getUnit();
      if (unit === "metric") {
        els.lenHelp.textContent = "meters";
        els.widHelp.textContent = "meters";
        els.depthHelp.textContent = "centimeters";
      } else {
        els.lenHelp.textContent = "feet";
        els.widHelp.textContent = "feet";
        els.depthHelp.textContent = "inches";
      }
      calculate();
    }

    function calculate() {
      const unit = getUnit();
      const L = num(els.len.value);
      const W = num(els.wid.value);
      const D = num(els.depth.value);
      let waste = num(els.waste.value);
      const density = num(els.density.value) || 1.6;

      if (!L || !W || !D || L <= 0 || W <= 0 || D <= 0) {
        els.results.innerHTML =
          "<p><strong>Please enter length, width and depth.</strong></p>";
        return;
      }

      if (waste < 0) waste = 0;
      if (waste > 30) waste = 30;

      let volumeM3, volumeFt3;

      if (unit === "metric") {
        const depthM = D / 100; // cm → m
        volumeM3 = L * W * depthM;
        volumeFt3 = volumeM3 / 0.0283168;
      } else {
        const depthFt = D / 12; // in → ft
        volumeFt3 = L * W * depthFt;
        volumeM3 = volumeFt3 * 0.0283168;
      }

      const volumeM3Waste = volumeM3 * (1 + waste / 100);
      const tonnes = volumeM3Waste * density;
      const kg = tonnes * 1000;
      const usTons = tonnes * 1.10231;
      const cubicYards = volumeM3Waste * 1.30795;

      els.results.innerHTML = `
        <p><strong>Net volume:</strong> ${volumeM3.toFixed(
          3
        )} m³ (${volumeFt3.toFixed(1)} ft³)</p>
        <p><strong>Volume incl. ${waste.toFixed(
          0
        )}% waste:</strong> ${volumeM3Waste.toFixed(3)} m³ (~${cubicYards.toFixed(
        2
      )} yd³)</p>
        <p><strong>Estimated weight:</strong> ${tonnes.toFixed(
          2
        )} tonnes (${kg.toFixed(0)} kg, ~${usTons.toFixed(2)} US tons)</p>
      `;
    }

    unitRadios.forEach((r) => r.addEventListener("change", updateLabels));
    [els.len, els.wid, els.depth, els.waste, els.density].forEach((input) =>
      input.addEventListener("input", calculate)
    );

    updateLabels();
  })();

