scripts:
(function () {
    const els = {
      len: document.getElementById("mcpDwLen"),
      wid: document.getElementById("mcpDwWid"),
      height: document.getElementById("mcpDwHeight"),
      areaMode: document.getElementById("mcpDwIncludeCeiling"),
      preset: document.getElementById("mcpDwSheetPreset"),
      sheetLen: document.getElementById("mcpDwSheetLen"),
      sheetWid: document.getElementById("mcpDwSheetWid"),
      waste: document.getElementById("mcpDwWaste"),
      results: document.getElementById("mcpDwResults"),
      lenHelp: document.getElementById("mcpDwLenHelp"),
      widHelp: document.getElementById("mcpDwWidHelp"),
      heightHelp: document.getElementById("mcpDwHeightHelp"),
      sheetLenHelp: document.getElementById("mcpDwSheetLenHelp"),
      sheetWidHelp: document.getElementById("mcpDwSheetWidHelp")
    };

    const unitRadios = document.querySelectorAll("input[name='mcpDwUnits']");

    function getUnit() {
      for (const r of unitRadios) {
        if (r.checked) return r.value;
      }
      return "metric";
    }

    function num(v) {
      const n = parseFloat(v);
      return isNaN(n) ? 0 : n;
    }

    function updateLabels() {
      const unit = getUnit();
      if (unit === "metric") {
        els.lenHelp.textContent = "meters";
        els.widHelp.textContent = "meters";
        els.heightHelp.textContent = "meters (floor to ceiling)";
        els.sheetLenHelp.textContent = "meters (custom, optional)";
        els.sheetWidHelp.textContent = "meters (custom, optional)";
      } else {
        els.lenHelp.textContent = "feet";
        els.widHelp.textContent = "feet";
        els.heightHelp.textContent = "feet (floor to ceiling)";
        els.sheetLenHelp.textContent = "feet (custom, optional)";
        els.sheetWidHelp.textContent = "feet (custom, optional)";
      }
      calculate();
    }

    function getSheetSize(unit) {
      const preset = els.preset.value;
      let L = num(els.sheetLen.value);
      let W = num(els.sheetWid.value);

      if (preset === "metric_240x120" && unit === "metric") {
        L = 2.4;
        W = 1.2;
      } else if (preset === "metric_260x120" && unit === "metric") {
        L = 2.6;
        W = 1.2;
      } else if (preset === "imperial_8x4" && unit === "imperial") {
        L = 8;
        W = 4;
      } else if (preset === "imperial_10x4" && unit === "imperial") {
        L = 10;
        W = 4;
      }
      // If custom preset selected, we rely on custom values (L/W from inputs)

      return { L, W };
    }

    function calculate() {
      const unit = getUnit();
      const Lr = num(els.len.value);
      const Wr = num(els.wid.value);
      const H = num(els.height.value);
      const mode = els.areaMode.value;
      let waste = num(els.waste.value);

      if (!Lr || !Wr || !H || Lr <= 0 || Wr <= 0 || H <= 0) {
        els.results.innerHTML =
          "<p><strong>Please enter room length, width and wall height.</strong></p>";
        return;
      }

      if (waste < 0) waste = 0;
      if (waste > 25) waste = 25;

      // Wall area (all four walls)
      let wallArea;
      if (unit === "metric") {
        wallArea = 2 * (Lr + Wr) * H; // m²
      } else {
        wallArea = 2 * (Lr + Wr) * H; // ft²
      }

      // Ceiling area if included
      let ceilingArea = 0;
      if (mode === "walls_ceiling") {
        const baseArea = Lr * Wr;
        ceilingArea = baseArea;
      }

      let totalArea = wallArea + ceilingArea;

      // convert everything to m² for reporting
      let areaM2, areaFt2;
      if (unit === "metric") {
        areaM2 = totalArea;
        areaFt2 = totalArea * 10.7639;
      } else {
        areaFt2 = totalArea;
        areaM2 = totalArea * 0.092903;
      }

      const sheetSize = getSheetSize(unit);
      let sheetArea;
      if (unit === "metric") {
        sheetArea = sheetSize.L * sheetSize.W; // m²
      } else {
        sheetArea = sheetSize.L * sheetSize.W; // ft²
      }

      if (!sheetArea || sheetArea <= 0) {
        els.results.innerHTML =
          "<p><strong>Please select a sheet size or enter a valid custom size.</strong></p>";
        return;
      }

      // base sheets count
      let netSheets;
      if (unit === "metric") {
        netSheets = areaM2 / sheetArea;
      } else {
        netSheets = areaFt2 / sheetArea;
      }

      const sheetsWithWaste = netSheets * (1 + waste / 100);
      const totalSheets = Math.ceil(sheetsWithWaste);

      els.results.innerHTML = `
        <p><strong>Total surface area:</strong> ${areaM2.toFixed(
          2
        )} m² (${areaFt2.toFixed(0)} ft²)</p>
        <p><strong>Net sheets (no waste):</strong> ${Math.ceil(
          netSheets
        )} sheets</p>
        <p><strong>Sheets incl. ${waste.toFixed(
          0
        )}% waste:</strong> ${totalSheets} sheets</p>
      `;
    }

    unitRadios.forEach((r) => r.addEventListener("change", updateLabels));
    [
      els.len,
      els.wid,
      els.height,
      els.areaMode,
      els.preset,
      els.sheetLen,
      els.sheetWid,
      els.waste
    ].forEach((input) => input.addEventListener("input", calculate));

    updateLabels();
  })();

