(function () {
    const els = {
      len: document.getElementById("mcpRoofLen"),
      width: document.getElementById("mcpRoofWidth"),
      slope: document.getElementById("mcpRoofSlope"),
      waste: document.getElementById("mcpRoofWaste"),
      bundle: document.getElementById("mcpRoofBundle"),
      results: document.getElementById("mcpRoofResults"),
      lenHelp: document.getElementById("mcpRoofLenHelp"),
      widthHelp: document.getElementById("mcpRoofWidthHelp"),
      slopeHelp: document.getElementById("mcpRoofSlopeHelp"),
      bundleHelp: document.getElementById("mcpRoofBundleHelp")
    };

    const unitRadios = document.querySelectorAll("input[name='mcpRoofUnits']");

    function getUnit() {
      for (const r of unitRadios) {
        if (r.checked) return r.value;
      }
      return "metric";
    }

    function num(v) {
      const n = parseFloat(v);
      return isNaN(n) ? 0 : n;
    }

    function updateLabels() {
      const unit = getUnit();
      if (unit === "metric") {
        els.lenHelp.textContent = "meters along the ridge";
        els.widthHelp.textContent = "meters across the building";
        els.slopeHelp.textContent =
          "Degrees (e.g. 25–45° typical). Leave blank to ignore slope.";
        els.bundleHelp.textContent =
          "Metric: m² per bundle (typical 2.5–3 m²). Imperial: bundles per roofing square (~3).";
        if (!els.bundle.value) els.bundle.value = 3;
      } else {
        els.lenHelp.textContent = "feet along the ridge";
        els.widthHelp.textContent = "feet across the building";
        els.slopeHelp.textContent =
          "Degrees or use 0 to ignore slope. Typical roofs are 15–45°.";
        els.bundleHelp.textContent =
          "Imperial: bundles per roofing square (~3). Metric: m² per bundle if needed.";
        if (!els.bundle.value) els.bundle.value = 3;
      }
      calculate();
    }

    function calculate() {
      const unit = getUnit();
      const L = num(els.len.value);
      const W = num(els.width.value);
      let slopeDeg = num(els.slope.value);
      let waste = num(els.waste.value);
      const bundle = num(els.bundle.value);

      if (!L || !W || L <= 0 || W <= 0) {
        els.results.innerHTML =
          "<p><strong>Please enter building length and width.</strong></p>";
        return;
      }

      if (waste < 0) waste = 0;
      if (waste > 25) waste = 25;

      // Simple gable roof: two rectangles, each half the span
      // Base plan area for one side = L * (W / 2)
      // For both sides, the projection area = L * W
      // Adjust for slope using cos(angle): roofArea = planArea / cos(theta)
      const planArea = L * W;

      let roofAreaFlat = planArea; // if slope is 0 or not given
      if (slopeDeg > 0) {
        const theta = (slopeDeg * Math.PI) / 180;
        const cosT = Math.cos(theta);
        if (cosT > 0) {
          roofAreaFlat = planArea / cosT;
        }
      }

      const areaWithWaste = roofAreaFlat * (1 + waste / 100);

      let areaM2, areaFt2;

      if (unit === "metric") {
        areaM2 = roofAreaFlat;
        areaFt2 = roofAreaFlat * 10.7639;
      } else {
        areaFt2 = roofAreaFlat;
        areaM2 = roofAreaFlat * 0.092903;
      }

      // Roofing squares (100 ft²)
      const squares = areaFt2 / 100;
      const squaresWaste = areaWithWaste * (unit === "metric" ? 10.7639 : 1) / 100;

      let bundles = 0;
      let bundlesWithWaste = 0;

      if (unit === "metric") {
        // bundle = m² per bundle
        if (bundle > 0) {
          bundles = areaM2 / bundle;
          bundlesWithWaste = areaWithWaste / bundle;
        }
      } else {
        // bundle = bundles per square
        if (bundle > 0) {
          bundles = squares * bundle;
          bundlesWithWaste = squaresWaste * bundle;
        }
      }

      const bundlesText =
        bundle > 0
          ? `<p><strong>Approx. bundles required (incl. waste):</strong> ${Math.ceil(
              bundlesWithWaste
            )} bundles</p>`
          : "";

      els.results.innerHTML = `
        <p><strong>Roof area (no waste):</strong> ${areaM2.toFixed(
          2
        )} m² (${areaFt2.toFixed(0)} ft²)</p>
        <p><strong>Roof area incl. ${waste.toFixed(
          0
        )}% waste:</strong> ${areaWithWaste.toFixed(2)} ${
        unit === "metric" ? "m²" : "ft²"
      }</p>
        <p><strong>Roofing squares (approx.):</strong> ${squaresWaste.toFixed(
          2
        )} squares</p>
        ${bundlesText}
      `;
    }

    unitRadios.forEach((r) => r.addEventListener("change", updateLabels));
    [els.len, els.width, els.slope, els.waste, els.bundle].forEach((input) =>
      input.addEventListener("input", calculate)
    );

    updateLabels();
  })();

